mapper.update:
UPDATE store
SET holiday = #{holiday},
    notice = #{notice},
    state = #{state}
WHERE store_id = #{storeId}

mapper.select:
SELECT o.order_id AS orderId, o.customer_name AS customerName, o.order_time AS orderDate, o.amount AS totalPrice, o.state, GROUP_CONCAT(od.menu_name SEPARATOR ', ') AS menuList FROM orders o JOIN order_detail od ON o.order_id = od.order_id WHERE o.store_id = #{storeId}
AND o.state = #{state}
GROUP BY o.order_id ORDER BY o.order_time DESC

mapper.update:
UPDATE orders
SET state = #{state}
WHERE order_id = #{orderId}
